using UnityEngine;

/// <summary>
/// Define uma Melodia Selvagem — faixa musical especial encontrada pelo mundo
/// que desbloqueia no Jukebox e conta para os 100% do save.
///
/// <b>Fontes de obtenção:</b>
/// <list type="bullet">
///   <item>Collectible no mundo (pickup <see cref="WildMelodyPickup"/>).</item>
///   <item>Recompensa de missão (via <see cref="ChallengeReward"/> ou Action NPC).</item>
///   <item>Recompensa de desafio.</item>
/// </list>
///
/// <b>Montagem no Editor:</b>
/// - Criar via menu "Animals/Wild Melody Data".
/// - "melodyId": ID único (ex: "floresta_canto_noturno").
/// - "displayName": nome exibido no Jukebox.
/// - "area": AreaData da área onde esta melodia é encontrada (usada para
///   contagem de progresso por área — <see cref="AreaData.totalMelodies"/>).
/// - "clip": AudioClip da faixa (pode ser null se não tiver clip próprio —
///   o Jukebox toca o clip do JukeboxTrack equivalente).
/// </summary>
[CreateAssetMenu(menuName = "Animals/Wild Melody Data", fileName = "NewWildMelody")]
public class WildMelodyData : ScriptableObject
{
    [Header("Identidade")]
    [Tooltip("Identificador único desta melodia (ex: 'floresta_canto_noturno'). Usado para persistência.")]
    public string melodyId;

    [Tooltip("Nome mostrado no Jukebox ao desbloquear esta melodia.")]
    public string displayName;

    [Tooltip("Descrição curta (opcional) — mostrada no popup de coleta ou no Jukebox.")]
    [TextArea(1, 3)] public string description;

    [Tooltip("Ícone/sprite desta melodia (opcional).")]
    public Sprite icon;

    [Header("Área")]
    [Tooltip("Área do jogo onde esta melodia é encontrada — para contagem de progresso por área (AreaData.totalMelodies).")]
    public AreaData area;

    [Header("Áudio")]
    [Tooltip("Clip de áudio desta faixa. Pode ser null se a faixa apenas desbloqueia uma entrada existente no Jukebox.")]
    public AudioClip clip;
}
